use std::collections::HashMap;

struct Message {
    sender_id: String,
    content: String,
    timestamp: i64,
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let messages = vec![
        Message { sender_id: "Alice".to_string(), content: "Hey, are you free later?".to_string(), timestamp: 1001 },
        Message { sender_id: "Bob".to_string(), content: "Sure, what time works for everyone?".to_string(), timestamp: 1002 },
        Message { sender_id: "Alice".to_string(), content: "Maybe around 7 PM?".to_string(), timestamp: 1003 },
        Message { sender_id: "Charlie".to_string(), content: "Does anyone know the new group key?".to_string(), timestamp: 1004 },
        Message { sender_id: "Bob".to_string(), content: "Let's stick to a private channel for that.".to_string(), timestamp: 1005 },
    ];

    let mut grouped_messages: HashMap<String, Vec<Message>> = HashMap::new();

    for message in messages {
        grouped_messages.entry(message.sender_id.clone()).or_default().push(message);
    }

    println!("--- Messages Grouped by Sender ---n");

    for (sender, messages_list) in grouped_messages {
        println!("n[Sender: {}]", sender);
        for message in messages_list {
            println!("  Time {}: \"{}\"", message.timestamp, message.content);
        }
    }

    Ok(())
}

use std::collections::HashSet;

fn main() {
    let all_tokens = vec!["int".to_string(), "if".to_string(), "x".to_string(), "while".to_string(), "y".to_string(), "==".to_string()];
    let keywords: HashSet<String> = vec!["int".to_string(), "if".to_string(), "while".to_string()].into_iter().collect();

    let mut keywords_found = Vec::new();
    let mut identifiers_found = Vec::new();

    for token in all_tokens {
        if keywords.contains(&token) {
            keywords_found.push(token);
        } else if token == "==".to_string() {
            // Special handling for operators that aren't keywords but are distinct enough to be grouped separately
            identifiers_found.push(token);
        } else {
            identifiers_found.push(token); 
        }
    }

    println!("Keywords: {:?}", keywords_found);
    println!("Identifiers/Operators: {:?}", identifiers_found);
}

use std::collections::HashMap;

struct Record {
    key_value: String,
    is_valid: bool,
}

fn process_records(records: Vec<Record>) -> (HashMap<String, Vec<Record>>, Vec<Record>)
{
    let mut grouped_map = HashMap::new();
    let mut filtered_list = Vec::new();

    for record in records.into_iter()
    {
        if record.is_valid
        {
            grouped_map
                .entry(record.key_value.clone())
                .or_insert_with(Vec::new)
                .push(record);
        }
        else
        {
            filtered_list.push(Record {
                key_value: record.key_value,
                is_valid: false,
            });
        }
    }

    (grouped_map, filtered_list)
}

use std::collections::HashMap;

struct ProductRecord {
    category: String,
    embedding: Vec<f32>,
}

fn main() {
    let records = vec![ 
        ProductRecord { category: "Electronics".to_string(), embedding: vec![0.1, 0.2] },
        ProductRecord { category: "Books".to_string(), embedding: vec![-0.5, 0.8] },
        ProductRecord { category: "Electronics".to_string(), embedding: vec![0.3, -0.1] },
        ProductRecord { category: "Apparel".to_string(), embedding: vec![0.7, 0.2] },
        ProductRecord { category: "Books".to_string(), embedding: vec![-0.4, 0.9] },
    ];

    let mut grouped_embeddings: HashMap<String, Vec<Vec<f32>>> = HashMap::new();

    for record in records {
        grouped_embeddings.entry(record.category) 
            .or_default() 
            .push(record.embedding);
    }

    println!("Grouped Embeddings:");
    for (category, embeddings) in grouped_embeddings {
        println!("nCategory: {}", category);
        for embedding in embeddings {
            println!("  Embedding: {:?}", embedding);
        }
    }
}

use std::collections::HashMap;
use std::net::Ipv4Addr;

struct Packet {
    source_ip: Ipv4Addr,
    size: usize,
}

fn group_packets(packets: Vec<Packet>) -> HashMap<Ipv4Addr, Vec<usize>> {
    let mut groups: HashMap<Ipv4Addr, Vec<usize>> = HashMap::new();
    for packet in packets {
        groups.entry(packet.source_ip).or_default().push(packet.size);
    }
    groups
}

fn main() {
    let network_data = vec![ 
        Packet { source_ip: Ipv4Addr::new(192, 168, 1, 1), size: 150 },
        Packet { source_ip: Ipv4Addr::new(192, 168, 1, 2), size: 64 },
        Packet { source_ip: Ipv4Addr::new(192, 168, 1, 1), size: 200 },
        Packet { source_ip: Ipv4Addr::new(192, 168, 1, 3), size: 128 },
    ];

    let result = group_packets(network_data);

    for (ip, sizes) in result.iter() {
        println!("Source IP {}: Processed {} packets with total size info.", ip, sizes.len());
    }
}
